@dataclass
class ModelSpec:
    scheme: str
    bucket: str
    prefix: str
    region: Optional[str] = None


def parse_s3_uri(uri: str) -> ModelSpec:
    if not uri or not isinstance(uri, str):
        raise ValueError("MODEL_PATH must be a non-empty string")
    m = re.match(r"^s3://([^/]+)/?(.*)$", uri.strip())
    if not m:
        raise ValueError("Only s3:// URIs are supported for MODEL_PATH")
    bucket = m.group(1)
    prefix = m.group(2) or ""
    return ModelSpec(scheme="s3", bucket=bucket, prefix=prefix, region=os.getenv("AWS_REGION") or os.getenv("AWS_DEFAULT_REGION"))


def normalize_prefix(prefix: str) -> str:
    prefix = prefix.lstrip("/")
    return prefix


def is_version_dir(name: str) -> bool:
    # Accept: v1, v001, 1, 20240101, 2024-01-01, 1.2.3, etc.
    if not name:
        return False
    return bool(re.match(r"^(v?\d+([._-]\d+)*|\d{4}([._-]\d{2}){2}([._-]\d{2}){0,1})$", name))


def extract_version_key(name: str) -> Tuple[int, List[int], str]:
    # Returns (priority, numeric_parts, original) for sorting.
    # Higher priority sorts later.
    s = name.strip()
    s2 = s[1:] if s.lower().startswith("v") else s
    parts = re.split(r"[._-]", s2)
    nums = []
    for p in parts:
        try:
            nums.append(int(p))
        except Exception:
            nums.append(-1)
    priority = 1 if all(n >= 0 for n in nums) else 0
    return (priority, nums, s)


def ensure_trailing_slash(prefix: str) -> str:
    if prefix and not prefix.endswith("/"):
        return prefix + "/"
    return prefix


def s3_client(region: Optional[str] = None):
    cfg = Config(
        retries={"max_attempts": int(os.getenv("AWS_MAX_ATTEMPTS", "10")), "mode": "standard"},
        connect_timeout=int(os.getenv("AWS_CONNECT_TIMEOUT", "10")),
        read_timeout=int(os.getenv("AWS_READ_TIMEOUT", "60")),
    )
    if region:
        return boto3.client("s3", region_name=region, config=cfg)
    return boto3.client("s3", config=cfg)


def list_common_prefixes(s3, bucket: str, prefix: str) -> List[str]:
    prefix = normalize_prefix(prefix)
    prefix = ensure_trailing_slash(prefix) if prefix else ""
    paginator = s3.get_paginator("list_objects_v2")
    cps = []
    for page in paginator.paginate(Bucket=bucket, Prefix=prefix, Delimiter="/"):
        for cp in page.get("CommonPrefixes", []) or []:
            p = cp.get("Prefix", "")
            if p:
                cps.append(p)
    return cps


def list_objects(s3, bucket: str, prefix: str) -> List[dict]:
    prefix = normalize_prefix(prefix)
    paginator = s3.get_paginator("list_objects_v2")
    objs = []
    for page in paginator.paginate(Bucket=bucket, Prefix=prefix):
        for obj in page.get("Contents", []) or []:
            objs.append(obj)
    return objs


def pick_latest_version_prefix(s3, bucket: str, base_prefix: str) -> str:
    base_prefix = normalize_prefix(base_prefix)
    base_prefix = ensure_trailing_slash(base_prefix) if base_prefix else ""
    cps = list_common_prefixes(s3, bucket, base_prefix)

    candidates = []
    for p in cps:
        rel = p[len(base_prefix):].strip("/")
        if is_version_dir(rel):
            candidates.append((extract_version_key(rel), p))

    if candidates:
        candidates.sort(key=lambda x: x[0])
        return candidates[-1][1]

    # Fallback: choose by latest modified object under base_prefix
    objs = list_objects(s3, bucket, base_prefix)
    if not objs:
        raise FileNotFoundError(f"No model objects found under s3://{bucket}/{base_prefix}")
    objs.sort(key=lambda o: o.get("LastModified"))
    latest_key = objs[-1]["Key"]
    # Use directory containing the latest object
    if "/" in latest_key[len(base_prefix):]:
        dir_prefix = base_prefix + latest_key[len(base_prefix):].split("/")[0] + "/"
        return dir_prefix
    return base_prefix


def choose_model_artifact_key(s3, bucket: str, version_prefix: str) -> str:
    version_prefix = normalize_prefix(version_prefix)
    objs = list_objects(s3, bucket, version_prefix)
    if not objs:
        raise FileNotFoundError(f"No objects found under s3://{bucket}/{version_prefix}")

    preferred_exts = [".joblib", ".pkl", ".pickle", ".pt", ".pth", ".onnx"]
    preferred_names = ["model", "model.joblib", "model.pkl", "model.pickle", "model.onnx", "model.pt", "model.pth"]

    def score(obj):
        key = obj["Key"]
        name = os.path.basename(key).lower()
        ext = os.path.splitext(name)[1]
        s = 0
        if name in preferred_names:
            s += 1000
        if ext in preferred_exts:
            s += 100
        s += int(obj.get("Size", 0) > 0) * 10
        lm = obj.get("LastModified")
        return (s, lm)

    objs.sort(key=score)
    return objs[-1]["Key"]


def download_s3_object(s3, bucket: str, key: str, dest_path: str):
    os.makedirs(os.path.dirname(dest_path), exist_ok=True)
    s3.download_file(bucket, key, dest_path)


def atomic_replace_dir(src_dir: str, dst_dir: str):
    parent = os.path.dirname(dst_dir.rstrip(os.sep)) or "."
    os.makedirs(parent, exist_ok=True)
    tmp_dst = dst_dir.rstrip(os.sep) + ".tmp." + str(int(time.time() * 1000))
    if os.path.exists(tmp_dst):
        shutil.rmtree(tmp_dst, ignore_errors=True)
    shutil.move(src_dir, tmp_dst)
    if os.path.exists(dst_dir):
        shutil.rmtree(dst_dir, ignore_errors=True)
    shutil.move(tmp_dst, dst_dir)


def load_model_from_file(path: str):
    ext = os.path.splitext(path)[1].lower()
    if ext in (".joblib",) and joblib is not None:
        return joblib.load(path)
    if ext in (".pkl", ".pickle") and pickle is not None:
        with open(path, "rb") as f:
            return pickle.load(f)
    # For other formats, return path as handle
    return {"artifact_path": path, "format": ext or "unknown"}


class ModelManager:
    def __init__(self, model_uri: str, cache_dir: Optional[str] = None):
        self.model_uri = model_uri
        self.spec = parse_s3_uri(model_uri)
        self.s3 = s3_client(self.spec.region)
        self.cache_dir = cache_dir or os.getenv("MODEL_CACHE_DIR") or os.path.join(tempfile.gettempdir(), "model_cache")
        self.active_dir = os.path.join(self.cache_dir, "active")
        self.meta_path = os.path.join(self.active_dir, "meta.json")
        self.model = None
        self.model_info = None

    def fetch_latest(self) -> dict:
        base_prefix = normalize_prefix(self.spec.prefix)
        version_prefix = pick_latest_version_prefix(self.s3, self.spec.bucket, base_prefix)
        artifact_key = choose_model_artifact_key(self.s3, self.spec.bucket, version_prefix)

        with tempfile.TemporaryDirectory(prefix="model_dl_") as tmp:
            local_dir = os.path.join(tmp, "model")
            os.makedirs(local_dir, exist_ok=True)
            local_artifact = os.path.join(local_dir, os.path.basename(artifact_key))
            download_s3_object(self.s3, self.spec.bucket, artifact_key, local_artifact)

            meta = {
                "model_uri": self.model_uri,
                "bucket": self.spec.bucket,
                "base_prefix": base_prefix,
                "version_prefix": version_prefix,
                "artifact_key": artifact_key,
                "downloaded_at": int(time.time()),
                "local_artifact": os.path.basename(artifact_key),
            }
            with open(os.path.join(local_dir, "meta.json"), "w", encoding="utf-8") as f:
                json.dump(meta, f, indent=2, sort_keys=True)

            if os.path.exists(self.active_dir):
                shutil.rmtree(self.active_dir, ignore_errors=True)
            os.makedirs(self.cache_dir, exist_ok=True)
            atomic_replace_dir(local_dir, self.active_dir)

        return meta

    def load_active(self):
        if not os.path.exists(self.meta_path):
            raise FileNotFoundError("No active model found; fetch_latest must be called first")
        with open(self.meta_path, "r", encoding="utf-8") as f:
            meta = json.load(f)
        artifact_path = os.path.join(self.active_dir, meta["local_artifact"])
        self.model = load_model_from_file(artifact_path)
        self.model_info = meta
        return self.model

    def startup(self):
        meta = self.fetch_latest()
        model = self.load_active()
        return model, meta


